// Pega todos os operadores do banco
const operadores = $('Buscar Operadores').all().map(item => item.json);

// Pega todas as linhas do Excel
const linhas = $('Processar Excel').all();

// Normaliza texto para comparação
const norm = s => String(s || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/\s+/g, ' ')
  .trim();

// Converte número no formato brasileiro
const parseBR = s => {
  if (!s && s !== 0) return 0;
  s = String(s).replace(/%/g, '').trim();
  if (!s) return 0;
  if (s.startsWith(',')) s = '0' + s;
  if (s.includes(',')) {
    s = s.replace(/\./g, '').replace(',', '.');
  } else if (/^\d{1,3}(\.\d{3})+$/.test(s)) {
    s = s.replace(/\./g, '');
  }
  return parseFloat(s) || 0;
};

// Meses abreviados
const MESES = { jan:1, fev:2, mar:3, abr:4, mai:5, jun:6, jul:7, ago:8, set:9, out:10, nov:11, dez:12 };

const resultado = [];
const erros = [];

for (const linha of linhas) {
  const row = linha.json;

  // Pula linhas vazias
  const operadorNome = String(row['Operador'] || row['operador'] || '').trim();
  if (!operadorNome) continue;

  // Descobre o mês (aceita número 1-12 ou abreviatura)
  let mes = parseInt(row['Mes'] || row['mes'] || row['Mês'] || 0);
  if (!mes) {
    const mesStr = String(row['Mes'] || row['mes'] || row['Mês'] || '').toLowerCase().substring(0, 3);
    mes = MESES[mesStr] || 0;
  }
  if (!mes || mes < 1 || mes > 12) {
    erros.push({ linha: operadorNome, erro: 'Mês inválido: ' + (row['Mes'] || row['mes']) });
    continue;
  }

  const ano = parseInt(row['Ano'] || row['ano'] || new Date().getFullYear());

  // Faz match do operador
  const normNome = norm(operadorNome);
  const op = operadores.find(o => {
    const normOp = norm(o.nome);
    const primeiroNomePDF = normNome.split(' ')[0];
    const ultimoNomePDF  = normNome.split(' ').pop();
    const primeiroNomeDB = normOp.split(' ')[0];
    return normNome.includes(normOp)
      || normOp.includes(normNome)
      || (primeiroNomePDF === primeiroNomeDB && normNome.includes(ultimoNomePDF) && normOp.includes(ultimoNomePDF));
  });

  if (!op) {
    erros.push({ linha: operadorNome, erro: 'Operador não encontrado no banco' });
    continue;
  }

  resultado.push({
    json: {
      operador_id:        op.id,
      operador_nome:      op.nome,
      ano,
      mes,
      giros_totais:       parseBR(row['Giros Totais']       || row['giros_totais']),
      giros_bons:         parseBR(row['Giros Bons']         || row['giros_bons']),
      h_produtivas:       parseBR(row['H Produtivas']       || row['H.Produtivas']  || row['h_produtivas']),
      h_acerto:           parseBR(row['H Acerto']           || row['H.Acerto']      || row['h_acerto']),
      h_improdutivas:     parseBR(row['H Improdutivas']     || row['H.Improd']      || row['h_improdutivas']),
      velocidade_media:   parseBR(row['Velocidade Media']   || row['Velocidade Média'] || row['velocidade_media']),
      qtd_acertos:        parseBR(row['Qtd Acertos']        || row['qtd_acertos']),
      desperdicio_acerto: parseBR(row['Desp Acerto']        || row['Desperdicio Acerto'] || row['desperdicio_acerto']),
      desperdicio_virando:parseBR(row['Desp Virando']       || row['Desperdicio Virando'] || row['desperdicio_virando']),
    }
  });
}

if (erros.length) {
  console.log('Linhas com erro:', JSON.stringify(erros));
}

console.log(`Processados: ${resultado.length} registros, Erros: ${erros.length}`);
return resultado;

const items = $input.all();
const total = items.length;
console.log(`✅ ${total} registros salvos com sucesso!`);
return [{ json: { status: 'ok', total_importados: total, timestamp: new Date().toISOString() } }];
